function smp_vp_display_dashboard_tab(array $tabs): array { $tabs["display-cards"] = "Display Cards"; return $tabs; }
function smp_vp_render_display_dashboard_tab($rendered, string $tab_id) { if ("display-cards" !== $tab_id) { return $rendered; } smp_vp_display_render_settings(); return true; }

function smp_vp_display_templates(): array {
    return [
        "boxed-row" => ["label" => "Boxed Row", "class" => "vp-a", "description" => "Bordered white cards with portrait, badge, name, role, and link."],
        "centered-stack" => ["label" => "Centered Stack", "class" => "vp-b", "description" => "Centered portrait with stacked name, role, and link."],
        "directory-list" => ["label" => "Directory List", "class" => "vp-c", "description" => "Full width rows with hairline dividers and right side link."],
        "minimal-quiet" => ["label" => "Minimal Quiet", "class" => "vp-d", "description" => "Compact rows with small portraits and no borders."],
        "accent-rule" => ["label" => "Accent Rule Cards", "class" => "vp-e", "description" => "Two up cards with soft ground and left accent rule."],
    ];
}

function smp_vp_display_defaults(): array {
    return ["enabled" => true, "append_to_content" => true, "homepage_template" => "boxed-row", "post_template" => "boxed-row", "profile_limit" => 7, "require_thumbnail" => false, "archive_url" => home_url("/profiles/"), "primary_color" => "#b3272d", "ink_color" => "#151515", "muted_color" => "#747474", "line_color" => "#e6e1de", "soft_color" => "#faf7f5"];
}
function smp_vp_display_settings(): array { $stored = get_option(SMP_VP_DISPLAY_OPTION, []); return array_replace(smp_vp_display_defaults(), is_array($stored) ? $stored : []); }
function smp_vp_display_sanitize(array $input): array {
    $s = smp_vp_display_settings(); $templates = array_keys(smp_vp_display_templates());
    $s["enabled"] = ! empty($input["enabled"]); $s["append_to_content"] = ! empty($input["append_to_content"]); $s["require_thumbnail"] = ! empty($input["require_thumbnail"]);
    $s["homepage_template"] = in_array((string)($input["homepage_template"] ?? ""), $templates, true) ? (string)$input["homepage_template"] : "boxed-row";
    $s["post_template"] = in_array((string)($input["post_template"] ?? ""), $templates, true) ? (string)$input["post_template"] : "boxed-row";
    $s["profile_limit"] = max(1, min(30, absint($input["profile_limit"] ?? 7))); $s["archive_url"] = esc_url_raw((string)($input["archive_url"] ?? home_url("/profiles/")));
    foreach (["primary_color", "ink_color", "muted_color", "line_color", "soft_color"] as $key) { $color = sanitize_hex_color((string)($input[$key] ?? $s[$key])); if ($color) { $s[$key] = $color; } }
    return $s;
}
function smp_vp_display_css(): string {
    return ".smp-vp-display{--vp-red:#b3272d;--vp-ink:#151515;--vp-muted:#747474;--vp-line:#e6e1de;--vp-soft:#faf7f5;max-width:1080px;margin:0 auto;padding:34px 0}.smp-vp-display .vp-head{display:flex;align-items:center;justify-content:space-between;padding:18px 0;border-bottom:1px solid var(--vp-line)}.smp-vp-display .lbl,.smp-vp-display .all,.smp-vp-display .vp-role,.smp-vp-display .vp-cta{font-size:11px;letter-spacing:.14em;text-transform:uppercase}.smp-vp-display .lbl,.smp-vp-display .vp-role,.smp-vp-display .all{color:var(--vp-muted)}.smp-vp-display a{text-decoration:none}.smp-vp-display svg{width:14px;height:14px;stroke:currentColor;fill:none;stroke-width:2}.smp-vp-display .vp-av{position:relative;flex-shrink:0}.smp-vp-display .vp-av img{border-radius:50%;object-fit:cover;filter:grayscale(100%);display:block;background:#f3f3f3}.smp-vp-display .vp-card:hover img{filter:grayscale(0)}.smp-vp-display .vp-badge{position:absolute;right:-3px;bottom:-3px;width:20px;height:20px;background:#fff;border-radius:50%;color:var(--vp-red);display:flex;align-items:center;justify-content:center}.smp-vp-display .vp-name{font-family:Playfair Display,Georgia,serif;font-weight:700;font-size:18px;color:var(--vp-ink);line-height:1.2}.smp-vp-display .vp-card:hover .vp-name,.smp-vp-display .vp-cta{color:var(--vp-red)}.smp-vp-display .vp-a,.smp-vp-display .vp-b,.smp-vp-display .vp-d,.smp-vp-display .vp-e{display:grid;gap:20px;padding:32px 0}.smp-vp-display .vp-a{grid-template-columns:repeat(3,1fr)}.smp-vp-display .vp-b{grid-template-columns:repeat(3,1fr)}.smp-vp-display .vp-d{grid-template-columns:repeat(4,1fr);gap:6px 28px}.smp-vp-display .vp-e{grid-template-columns:repeat(2,1fr)}.smp-vp-display .vp-a .vp-card{display:flex;align-items:center;gap:18px;border:1px solid var(--vp-line);background:#fff;padding:20px}.smp-vp-display .vp-b .vp-card{display:flex;flex-direction:column;align-items:center;text-align:center;border:1px solid var(--vp-line);background:#fff;padding:30px 20px}.smp-vp-display .vp-c{padding:14px 0 32px}.smp-vp-display .vp-c .vp-card{display:flex;align-items:center;gap:18px;padding:18px 4px;border-bottom:1px solid var(--vp-line)}.smp-vp-display .vp-c .vp-meta{flex:1}.smp-vp-display .vp-d .vp-card{display:flex;align-items:center;gap:14px;padding:18px 2px;border-top:1px solid var(--vp-line)}.smp-vp-display .vp-e .vp-card{display:flex;align-items:center;gap:20px;background:var(--vp-soft);border-left:3px solid var(--vp-red);padding:22px 24px}.smp-vp-display .vp-a img{width:66px;height:66px}.smp-vp-display .vp-b img{width:84px;height:84px}.smp-vp-display .vp-c img{width:58px;height:58px}.smp-vp-display .vp-d img{width:52px;height:52px}.smp-vp-display .vp-e img{width:88px;height:88px}@media(max-width:900px){.smp-vp-display .vp-a,.smp-vp-display .vp-b,.smp-vp-display .vp-d,.smp-vp-display .vp-e{grid-template-columns:repeat(2,1fr)}}@media(max-width:620px){.smp-vp-display .vp-a,.smp-vp-display .vp-b,.smp-vp-display .vp-d,.smp-vp-display .vp-e{grid-template-columns:1fr}}";
}
function smp_vp_display_render_settings(): void {
    if (! current_user_can("manage_options")) { ?><div class="notice notice-error"><p>Insufficient permissions.</p></div><?php return; }
    $s = smp_vp_display_settings(); $templates = smp_vp_display_templates(); $nonce = wp_create_nonce(SMP_VP_DISPLAY_NONCE); $preview = smp_vp_display_preview_profiles(); ?>
    <style>.smp-vp-display-admin{max-width:1240px}.smp-vp-display-admin .card{background:#fff;border:1px solid #dcdcde;border-radius:10px;padding:18px;margin:16px 0}.smp-vp-display-admin .grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}.smp-vp-display-admin label{font-weight:700;display:block;margin-bottom:6px}.smp-vp-display-admin input,.smp-vp-display-admin select{width:100%;min-height:38px}.smp-vp-display-admin .checks,.smp-vp-display-admin .actions{display:flex;gap:14px;flex-wrap:wrap;margin-top:14px}.smp-vp-display-admin .log{min-height:44px;border:1px solid #dcdcde;background:#f6f7f7;border-radius:8px;padding:10px;margin-top:12px;font-family:Menlo,Consolas,monospace}.template-preview{border:1px solid #dcdcde;border-radius:10px;padding:16px;margin:16px 0;background:#fff}<?php echo smp_vp_display_css(); ?></style>
    <div class="smp-vp-display-admin" id="smp-vp-display-settings" data-nonce="<?php echo esc_attr($nonce); ?>"><div class="card"><h2>Verified Profile Display Cards</h2><p>Template selection lives inside the Verified Profiles plugin and replaces JetEngine dependent profile cards.</p><div class="grid"><div><label>Homepage template</label><select id="smp-vp-homepage-template"><?php foreach ($templates as $key => $tpl) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($s["homepage_template"], $key); ?>><?php echo esc_html($tpl["label"]); ?></option><?php endforeach; ?></select></div><div><label>Post entity template</label><select id="smp-vp-post-template"><?php foreach ($templates as $key => $tpl) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($s["post_template"], $key); ?>><?php echo esc_html($tpl["label"]); ?></option><?php endforeach; ?></select></div><div><label>Homepage limit</label><input id="smp-vp-profile-limit" type="number" min="1" max="30" value="<?php echo esc_attr($s["profile_limit"]); ?>"></div><div><label>Archive URL</label><input id="smp-vp-archive-url" type="text" value="<?php echo esc_attr($s["archive_url"]); ?>"></div><?php foreach (["primary_color"=>"Primary", "ink_color"=>"Text", "muted_color"=>"Muted", "line_color"=>"Line", "soft_color"=>"Soft background"] as $key => $label) : ?><div><label><?php echo esc_html($label); ?></label><input id="smp-vp-<?php echo esc_attr(str_replace("_", "-", $key)); ?>" type="color" value="<?php echo esc_attr($s[$key]); ?>"></div><?php endforeach; ?></div><div class="checks"><label><input id="smp-vp-display-enabled" type="checkbox" <?php checked($s["enabled"]); ?>> Enable cards</label><label><input id="smp-vp-append-content" type="checkbox" <?php checked($s["append_to_content"]); ?>> Append to posts and press releases</label><label><input id="smp-vp-require-thumb" type="checkbox" <?php checked($s["require_thumbnail"]); ?>> Require thumbnails</label></div><div class="actions"><button type="button" class="button button-primary" id="smp-vp-display-save">Save display settings</button><button type="button" class="button" id="smp-vp-import-elementor">Import Elementor colors</button></div><div class="log" id="smp-vp-display-log">Ready.</div></div><div class="card"><h2>Template Previews</h2><?php foreach ($templates as $key => $tpl) : ?><div class="template-preview"><h3><?php echo esc_html($tpl["label"]); ?></h3><p><?php echo esc_html($tpl["description"]); ?></p><?php echo smp_vp_display_render_collection($preview, ["template" => $key, "show_head" => false]); ?></div><?php endforeach; ?></div></div>
    <script>jQuery(function($){function collect(){return{enabled:$("#smp-vp-display-enabled").is(":checked")?1:0,append_to_content:$("#smp-vp-append-content").is(":checked")?1:0,require_thumbnail:$("#smp-vp-require-thumb").is(":checked")?1:0,homepage_template:$("#smp-vp-homepage-template").val(),post_template:$("#smp-vp-post-template").val(),profile_limit:$("#smp-vp-profile-limit").val(),archive_url:$("#smp-vp-archive-url").val(),primary_color:$("#smp-vp-primary-color").val(),ink_color:$("#smp-vp-ink-color").val(),muted_color:$("#smp-vp-muted-color").val(),line_color:$("#smp-vp-line-color").val(),soft_color:$("#smp-vp-soft-color").val()};}function log(m){$("#smp-vp-display-log").text(m||"Done.");}$("#smp-vp-display-save").on("click",function(){var b=$(this),t=b.text();b.prop("disabled",true).text("Saving...");$.post(ajaxurl,{action:"smp_vp_display_save_settings",nonce:$("#smp-vp-display-settings").data("nonce"),settings:collect()}).done(function(r){log(r&&r.success?r.data.message:((r.data&&r.data.message)||"Save failed."));}).fail(function(){log("Save request failed.");}).always(function(){b.prop("disabled",false).text(t);});});$("#smp-vp-import-elementor").on("click",function(){var b=$(this),t=b.text();b.prop("disabled",true).text("Importing...");$.post(ajaxurl,{action:"smp_vp_display_import_elementor",nonce:$("#smp-vp-display-settings").data("nonce")}).done(function(r){log(r&&r.success?r.data.message:((r.data&&r.data.message)||"Import failed."));}).fail(function(){log("Import request failed.");}).always(function(){b.prop("disabled",false).text(t);});});});</script>
    <?php
}

function smp_vp_ajax_display_save_settings(): void { if (! current_user_can("manage_options")) { wp_send_json_error(["message"=>"Insufficient permissions."],403); } check_ajax_referer(SMP_VP_DISPLAY_NONCE,"nonce"); $input = isset($_POST["settings"]) && is_array($_POST["settings"]) ? wp_unslash($_POST["settings"]) : []; $s = smp_vp_display_sanitize($input); update_option(SMP_VP_DISPLAY_OPTION,$s,false); wp_send_json_success(["message"=>"Display settings saved.","settings"=>$s]); }
function smp_vp_ajax_display_import_elementor(): void { if (! current_user_can("manage_options")) { wp_send_json_error(["message"=>"Insufficient permissions."],403); } check_ajax_referer(SMP_VP_DISPLAY_NONCE,"nonce"); $colors = smp_vp_display_elementor_colors(); if (empty($colors)) { wp_send_json_error(["message"=>"No Elementor colors found."],404); } $s = array_replace(smp_vp_display_settings(),$colors); update_option(SMP_VP_DISPLAY_OPTION,$s,false); wp_send_json_success(["message"=>"Elementor colors imported.","settings"=>$s]); }
function smp_vp_display_elementor_colors(): array { $kit = absint(get_option("elementor_active_kit")); if (! $kit) { return []; } $raw = get_post_meta($kit,"_elementor_page_settings",true); if (! is_array($raw)) { return []; } $flat = []; foreach (["system_colors","custom_colors"] as $group) { foreach ((array)($raw[$group] ?? []) as $c) { if (! empty($c["_id"]) && ! empty($c["color"]) && sanitize_hex_color($c["color"])) { $flat[sanitize_key($c["_id"])] = sanitize_hex_color($c["color"]); } } } return array_filter(["primary_color"=>$flat["primary"] ?? $flat["accent"] ?? null,"ink_color"=>$flat["text"] ?? null,"muted_color"=>$flat["secondary"] ?? null]); }

function smp_vp_display_preview_profiles(): array { $ids = get_posts(["post_type"=>"profile","post_status"=>"publish","posts_per_page"=>6,"orderby"=>"modified","order"=>"DESC","fields"=>"ids"]); return $ids ? array_map("intval",$ids) : [["name"=>"Elena Marsh","role"=>"Founder and CEO","url"=>"#","image"=>"https://picsum.photos/seed/vp1/180/180?grayscale"],["name"=>"Priya Raman","role"=>"Operations Director","url"=>"#","image"=>"https://picsum.photos/seed/vp2/180/180?grayscale"],["name"=>"Aja Coleman","role"=>"Executive Director","url"=>"#","image"=>"https://picsum.photos/seed/vp3/180/180?grayscale"]]; }
function smp_vp_display_profile_data($profile): array { if (is_array($profile)) { return $profile; } $id = is_object($profile) && isset($profile->ID) ? (int)$profile->ID : (int)$profile; if (! $id) { return []; } $img = get_the_post_thumbnail_url($id,"medium"); return ["name"=>get_the_title($id),"role"=>smp_vp_display_profile_role($id),"url"=>get_permalink($id) ?: "#","image"=>$img ?: "https://picsum.photos/seed/" . rawurlencode(sanitize_title(get_the_title($id))) . "/180/180?grayscale"]; }
function smp_vp_display_profile_role(int $id): string { foreach (["title","job_title","role","occupation","profession"] as $f) { $v = function_exists("get_field") ? get_field($f,$id) : get_post_meta($id,$f,true); if (is_scalar($v) && trim((string)$v) !== "") { return trim(wp_strip_all_tags((string)$v)); } } return "Verified Profile"; }
function smp_vp_display_arrow_svg(): string { ob_start(); ?><svg viewBox="0 0 24 24"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg><?php return (string)ob_get_clean(); }
function smp_vp_display_badge_svg(): string { ob_start(); ?><svg viewBox="0 0 24 24"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg><?php return (string)ob_get_clean(); }
function smp_vp_display_render_card($profile,string $template): string { $d=smp_vp_display_profile_data($profile); if (empty($d["name"])) { return ""; } ob_start(); ?><a href="<?php echo esc_url($d["url"]); ?>" class="vp-card"><div class="vp-av"><img src="<?php echo esc_url($d["image"]); ?>" alt="<?php echo esc_attr($d["name"]); ?>"><span class="vp-badge"><?php echo smp_vp_display_badge_svg(); ?></span></div><?php if ("directory-list" === $template) : ?><div class="vp-meta"><div class="vp-name"><?php echo esc_html($d["name"]); ?></div><span class="vp-role"><?php echo esc_html($d["role"]); ?></span></div><div class="vp-cta">View Profile <?php echo smp_vp_display_arrow_svg(); ?></div><?php else : ?><div><div class="vp-name"><?php echo esc_html($d["name"]); ?></div><span class="vp-role"><?php echo esc_html($d["role"]); ?></span><?php if ("minimal-quiet" !== $template) : ?><div class="vp-cta">View Profile <?php echo smp_vp_display_arrow_svg(); ?></div><?php endif; ?></div><?php endif; ?></a><?php return (string)ob_get_clean(); }
function smp_vp_display_render_collection(array $profiles,array $args=[]): string { $s=array_replace(smp_vp_display_settings(),$args); $tpl=$s["template"] ?? $s["homepage_template"]; $templates=smp_vp_display_templates(); if (empty($templates[$tpl])) { $tpl="boxed-row"; } $vars=sprintf("--vp-red:%s;--vp-ink:%s;--vp-muted:%s;--vp-line:%s;--vp-soft:%s;",esc_attr($s["primary_color"]),esc_attr($s["ink_color"]),esc_attr($s["muted_color"]),esc_attr($s["line_color"]),esc_attr($s["soft_color"])); ob_start(); ?><style><?php echo smp_vp_display_css(); ?></style><section class="smp-vp-display" style="<?php echo esc_attr($vars); ?>"><?php if (($s["show_head"] ?? true)) : ?><div class="vp-head"><span class="lbl"><?php echo esc_html($s["title"] ?? "Verified Profiles"); ?></span><a class="all" href="<?php echo esc_url($s["archive_url"]); ?>">View Profiles <?php echo smp_vp_display_arrow_svg(); ?></a></div><?php endif; ?><div class="vp <?php echo esc_attr($templates[$tpl]["class"]); ?>"><?php foreach ($profiles as $p) { echo smp_vp_display_render_card($p,$tpl); } ?></div></section><?php return (string)ob_get_clean(); }
function smp_vp_display_homepage_ids(int $limit,bool $thumb): array { $args=["post_type"=>"profile","post_status"=>"publish","posts_per_page"=>$limit,"orderby"=>"modified","order"=>"DESC","fields"=>"ids"]; if ($thumb) { $args["meta_query"]=[["key"=>"_thumbnail_id","compare"=>"EXISTS"]]; } return array_map("intval",get_posts($args)); }
function smp_vp_display_post_ids(int $post_id,bool $thumb=false): array { $ids=[]; if (function_exists("get_field")) { foreach ((array)get_field("profiles",$post_id) as $row) { $v=is_array($row)?($row["profile"] ?? reset($row)):$row; if (is_object($v)&&isset($v->ID)) { $v=$v->ID; } if (absint($v)) { $ids[]=absint($v); } } } $ids=array_values(array_unique($ids)); return $thumb?array_values(array_filter($ids,static function($id){return has_post_thumbnail($id);})): $ids; }
function smp_vp_display_append_to_content(string $content): string { $s=smp_vp_display_settings(); if (empty($s["enabled"]) || empty($s["append_to_content"]) || is_admin() || ! is_singular(["post","press-release"]) || ! in_the_loop() || ! is_main_query()) { return $content; } $ids=smp_vp_display_post_ids((int)get_the_ID()); return $ids ? $content . smp_vp_display_render_collection($ids,["template"=>$s["post_template"],"title"=>"Verified Profiles"]) : $content; }
if (! function_exists(__NAMESPACE__ . "\display_homepage_profiles")) { function display_homepage_profiles($atts=[]): string { $s=smp_vp_display_settings(); $a=shortcode_atts(["limit"=>$s["profile_limit"],"template"=>$s["homepage_template"]],(array)$atts,"display_homepage_profiles"); $ids=smp_vp_display_homepage_ids(absint($a["limit"]),!empty($s["require_thumbnail"])); return $ids ? smp_vp_display_render_collection($ids,["template"=>$a["template"],"title"=>"Verified Profiles"]) : "<style>.display_home_profiles{display:none!important}</style>"; } }
if (! function_exists(__NAMESPACE__ . "\display_single_post_mentioned_in_article")) { function display_single_post_mentioned_in_article($atts=[]): string { $s=smp_vp_display_settings(); $a=shortcode_atts(["must_have_thumbnail"=>false,"template"=>$s["post_template"]],(array)$atts,"display_single_post_mentioned_in_article"); $ids=smp_vp_display_post_ids((int)get_the_ID(),filter_var($a["must_have_thumbnail"],FILTER_VALIDATE_BOOLEAN)); return $ids ? smp_vp_display_render_collection($ids,["template"=>$a["template"],"title"=>"Verified Profiles"]) : "<style>.display_single_post_mentioned_in_article{display:none!important}</style>"; } }
if (! function_exists(__NAMESPACE__ . "\display_profiles_featured_in_single_post")) { function display_profiles_featured_in_single_post(): string { return display_single_post_mentioned_in_article([]); } }
